CREATE TABLE live_validation_policies(policy_version TEXT PRIMARY KEY,policy_checksum TEXT NOT NULL CHECK(length(policy_checksum)=64),policy JSONB NOT NULL,created_at TIMESTAMP NOT NULL);
CREATE TABLE recommendation_snapshots_v2(recommendation_id UUID PRIMARY KEY,evaluation_id UUID NOT NULL REFERENCES recommendation_evaluations_v2(evaluation_id),candidate_id UUID NOT NULL REFERENCES opportunity_candidates_v2(candidate_id),recommendation_at TIMESTAMP NOT NULL,instrument_id UUID NOT NULL REFERENCES canonical_instruments(instrument_id),instrument_revision_id UUID NOT NULL REFERENCES canonical_instrument_revisions(revision_id),expiry DATE,strike NUMERIC,option_type TEXT,strategy_code TEXT NOT NULL,direction TEXT NOT NULL,holding_horizon TEXT NOT NULL,market_regime TEXT NOT NULL,liquidity_tier TEXT NOT NULL,entry_zone_low NUMERIC,entry_zone_high NUMERIC,stop_price NUMERIC,target_prices JSONB NOT NULL,predicted_win_probability NUMERIC,predicted_expected_value NUMERIC,prediction_low NUMERIC,prediction_high NUMERIC,evidence_quality_tier TEXT,effective_sample_size NUMERIC,reasons_for JSONB NOT NULL,reasons_against JSONB NOT NULL,feature_contributions JSONB NOT NULL,eligibility_state TEXT NOT NULL,recommendation_policy_reason TEXT NOT NULL,dataset_version TEXT,feature_version TEXT,outcome_model_version TEXT,similarity_model_version TEXT,opportunity_policy_version TEXT,calibration_policy_version TEXT NOT NULL,validation_state TEXT NOT NULL CHECK(validation_state IN ('ELIGIBLE','REJECTED','ABSTAINED')),operationally_trusted BOOLEAN NOT NULL DEFAULT FALSE CHECK(NOT operationally_trusted),lineage JSONB NOT NULL,lineage_checksum TEXT NOT NULL CHECK(length(lineage_checksum)=64),snapshotted_at TIMESTAMP NOT NULL,UNIQUE(evaluation_id));
CREATE TABLE recommendation_validation_observations_v2(observation_id UUID PRIMARY KEY,recommendation_id UUID NOT NULL REFERENCES recommendation_snapshots_v2(recommendation_id),bar_revision_id UUID NOT NULL REFERENCES historical_bar_revisions(bar_revision_id),manifest_id UUID NOT NULL REFERENCES historical_raw_manifests(manifest_id),observed_at TIMESTAMP NOT NULL,available_at TIMESTAMP NOT NULL,open_price NUMERIC NOT NULL,high_price NUMERIC NOT NULL,low_price NUMERIC NOT NULL,close_price NUMERIC NOT NULL,lineage_checksum TEXT NOT NULL CHECK(length(lineage_checksum)=64),UNIQUE(recommendation_id,bar_revision_id));
CREATE TABLE recommendation_fills_v2(fill_id UUID PRIMARY KEY,recommendation_id UUID NOT NULL REFERENCES recommendation_snapshots_v2(recommendation_id),fill_type TEXT NOT NULL CHECK(fill_type IN ('SIMULATED','USER_RECORDED')),fill_at TIMESTAMP NOT NULL,fill_price NUMERIC NOT NULL,fill_quality NUMERIC,slippage_pct NUMERIC,source TEXT NOT NULL,lineage_checksum TEXT NOT NULL CHECK(length(lineage_checksum)=64),UNIQUE(recommendation_id,fill_type,fill_at,fill_price));
CREATE TABLE recommendation_outcomes_v2(outcome_id UUID PRIMARY KEY,recommendation_id UUID NOT NULL REFERENCES recommendation_snapshots_v2(recommendation_id),as_of TIMESTAMP NOT NULL,state TEXT NOT NULL CHECK(state IN ('FILLED','UNFILLED','EXPIRED','UNRESOLVED','INSUFFICIENT_PATH','REJECTED','ABSTAINED')),entry_reached BOOLEAN,fill_id UUID REFERENCES recommendation_fills_v2(fill_id),terminal_reason TEXT,target_hit INTEGER,stop_hit BOOLEAN,first_touch TEXT,terminal_at TIMESTAMP,mfe_pct NUMERIC,mae_pct NUMERIC,realized_return_pct NUMERIC,net_return_pct NUMERIC,time_to_target_seconds BIGINT,time_to_stop_seconds BIGINT,time_under_water_seconds BIGINT,path_count INTEGER NOT NULL,failure_classification TEXT NOT NULL CHECK(failure_classification IN ('MARKET_FAILURE','MODEL_FAILURE','CALIBRATION_FAILURE','LIQUIDITY_FAILURE','FILL_FAILURE','EVENT_SHOCK','DATA_FAILURE','POLICY_REJECTION','UNCLASSIFIED','INSUFFICIENT_EVIDENCE')),lineage_checksum TEXT NOT NULL CHECK(length(lineage_checksum)=64),materialized_at TIMESTAMP NOT NULL,UNIQUE(recommendation_id,as_of));
CREATE TABLE recommendation_failure_classifications_v2(classification_id UUID PRIMARY KEY,outcome_id UUID NOT NULL REFERENCES recommendation_outcomes_v2(outcome_id),recommendation_id UUID NOT NULL REFERENCES recommendation_snapshots_v2(recommendation_id),classification TEXT NOT NULL,reason TEXT NOT NULL,evidence JSONB NOT NULL,lineage_checksum TEXT NOT NULL CHECK(length(lineage_checksum)=64),classified_at TIMESTAMP NOT NULL,UNIQUE(outcome_id));
CREATE TABLE validation_metric_runs_v2(run_id UUID PRIMARY KEY,policy_version TEXT NOT NULL REFERENCES live_validation_policies(policy_version),as_of TIMESTAMP NOT NULL,window_start TIMESTAMP NOT NULL,window_end TIMESTAMP NOT NULL,population_count INTEGER NOT NULL,metric_checksum TEXT NOT NULL CHECK(length(metric_checksum)=64),created_at TIMESTAMP NOT NULL,UNIQUE(policy_version,window_start,window_end,metric_checksum));
CREATE TABLE validation_metrics_v2(run_id UUID NOT NULL REFERENCES validation_metric_runs_v2(run_id),segment_type TEXT NOT NULL,segment_value TEXT NOT NULL,sample_size INTEGER NOT NULL,metrics JSONB NOT NULL,PRIMARY KEY(run_id,segment_type,segment_value));
CREATE TABLE validation_drift_evaluations_v2(evaluation_id UUID PRIMARY KEY,policy_version TEXT NOT NULL REFERENCES live_validation_policies(policy_version),as_of TIMESTAMP NOT NULL,shadow_session_count INTEGER NOT NULL,state TEXT NOT NULL CHECK(state IN ('HEALTHY','WATCH','DEGRADED','SUSPENDED','INSUFFICIENT_EVIDENCE')),drift_metrics JSONB NOT NULL,reasons JSONB NOT NULL,lineage_checksum TEXT NOT NULL CHECK(length(lineage_checksum)=64),created_at TIMESTAMP NOT NULL,UNIQUE(policy_version,as_of,lineage_checksum));
CREATE TABLE validation_policy_suspensions_v2(suspension_id UUID PRIMARY KEY,drift_evaluation_id UUID NOT NULL REFERENCES validation_drift_evaluations_v2(evaluation_id),policy_version TEXT NOT NULL REFERENCES live_validation_policies(policy_version),state TEXT NOT NULL CHECK(state='SUSPENDED'),reason TEXT NOT NULL,effective_at TIMESTAMP NOT NULL,lineage_checksum TEXT NOT NULL CHECK(length(lineage_checksum)=64),UNIQUE(drift_evaluation_id));
CREATE FUNCTION reject_live_validation_mutation() RETURNS trigger AS $$ BEGIN RAISE EXCEPTION 'Live recommendation validation evidence is immutable'; END; $$ LANGUAGE plpgsql;
CREATE TRIGGER live_validation_policies_immutable BEFORE UPDATE OR DELETE ON live_validation_policies FOR EACH ROW EXECUTE FUNCTION reject_live_validation_mutation();
CREATE TRIGGER recommendation_snapshots_immutable BEFORE UPDATE OR DELETE ON recommendation_snapshots_v2 FOR EACH ROW EXECUTE FUNCTION reject_live_validation_mutation();
CREATE TRIGGER recommendation_observations_immutable BEFORE UPDATE OR DELETE ON recommendation_validation_observations_v2 FOR EACH ROW EXECUTE FUNCTION reject_live_validation_mutation();
CREATE TRIGGER recommendation_fills_immutable BEFORE UPDATE OR DELETE ON recommendation_fills_v2 FOR EACH ROW EXECUTE FUNCTION reject_live_validation_mutation();
CREATE TRIGGER recommendation_outcomes_immutable BEFORE UPDATE OR DELETE ON recommendation_outcomes_v2 FOR EACH ROW EXECUTE FUNCTION reject_live_validation_mutation();
CREATE TRIGGER recommendation_failures_immutable BEFORE UPDATE OR DELETE ON recommendation_failure_classifications_v2 FOR EACH ROW EXECUTE FUNCTION reject_live_validation_mutation();
CREATE TRIGGER validation_metric_runs_immutable BEFORE UPDATE OR DELETE ON validation_metric_runs_v2 FOR EACH ROW EXECUTE FUNCTION reject_live_validation_mutation();
CREATE TRIGGER validation_metrics_immutable BEFORE UPDATE OR DELETE ON validation_metrics_v2 FOR EACH ROW EXECUTE FUNCTION reject_live_validation_mutation();
CREATE TRIGGER validation_drift_immutable BEFORE UPDATE OR DELETE ON validation_drift_evaluations_v2 FOR EACH ROW EXECUTE FUNCTION reject_live_validation_mutation();
CREATE TRIGGER validation_suspensions_immutable BEFORE UPDATE OR DELETE ON validation_policy_suspensions_v2 FOR EACH ROW EXECUTE FUNCTION reject_live_validation_mutation();
